import{_ as t,o as a,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"31. Remuneration And Remuneration Increases","description":"","frontmatter":{"title":"31. Remuneration And Remuneration Increases","eba":"Medical Specialists 2022-2026","topics":["wages","preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/wages/31-remuneration-and-remuneration-increases.md","filePath":"ebas/medical-specialists/wages/31-remuneration-and-remuneration-increases.md"}'),o={name:"ebas/medical-specialists/wages/31-remuneration-and-remuneration-increases.md"};function i(s,e,c,p,h,m){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_31-remuneration-and-remuneration-increases" tabindex="-1">31. Remuneration And Remuneration Increases <a class="header-anchor" href="#_31-remuneration-and-remuneration-increases" aria-label="Permalink to &quot;31. Remuneration And Remuneration Increases&quot;">​</a></h1><p><strong>31.1</strong> Weekly rates of pay will be increased by the amounts set out below:</p><p><strong>(a)</strong> 2.75% from the first pay period commencing on or after 1 March 2022;</p><p><strong>(b)</strong> 2.5% from the first pay period commencing on or after 1 September 2023;</p><p><strong>(c)</strong> 2.5% from the first pay period commencing on or after 1 March 2025.</p><p><strong>31.2</strong> The increases in rates of pay and other monetary entitlements specified in this Agreement have been agreed on the understanding that they will be the increases actually paid to the Doctors during the life of this Agreement. Where a Doctor’s remuneration has been negotiated as an annualised salary, the increase will apply to this annualised rate.</p><p><strong>31.3</strong> Existing work-related allowances will increase in accordance with the salary increases in subclause 31.1 above.</p><p><strong>31.4</strong> The weekly rates of pay and allowances for the life of this Agreement are set out in <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a>.</p><p><strong>31.5</strong> The increases in subclause 31.1 will not apply to private practice bonuses except where these have been included in a rolled up or annualised salary arrangement.</p><p><strong>31.6</strong> Patience in bargaining payment</p><p>At the commencement of this Agreement, all Existing Doctors will receive a once off lump sum payment of 2.5% of their ordinary wages calculated between 1 January 2022 and 28 February 2022.</p><p><strong>31.7</strong> Existing Doctors – pre-existing contracts</p><p><strong>(a)</strong> Where an Existing Doctor has, under a written contract entered into prior to 1 March 2022 (Contract), an entitlement to receive as at 1 March 2022 a rate of pay which is in excess of the rates specified in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> or an entitlement to receive as at 1 March 2022 a monetary payment which either exceeds the equivalent payment provided for in this Agreement or is a form of payment not provided for in this Agreement:</p><p><strong>(i)</strong> the Health Service may pay, and the Doctor may accept, the amount specified in the Contract as at 1 March 2022; and</p><p><strong>(ii)</strong> the Health Service must increase the actual contracted rate of pay in accordance with the percentage increases specified on the relevant dates as stated in subclauses 31.1; but</p><p><strong>(iii)</strong> the Health Service must not pay, and the Doctor must not seek or accept, any increase in the rates of pay or monetary payments as specified in the Contract as at 1 March 2022 which exceed the percentage increase in the rates of pay or monetary payments specified in this clause to apply at various times under this Agreement, and to the extent that the Contract otherwise provides, the Contract is unenforceable and of no effect.</p><p><strong>31.8</strong> Existing Doctors – change of position</p><p><strong>(a)</strong> Where an Existing Doctor is promoted or transferred by their Health Service to a different position with different or higher responsibilities, which position either existed at the commencement of this Agreement or has been created</p><p>in accordance with the Health Service&#39;s normal arrangements for the structuring and remuneration of positions (New Position), and the terms and conditions of the New Position are in accordance with the Health Service&#39;s normal arrangements for the structuring and remuneration of positions, the Health Service may offer the New Position to the Doctor on those terms and conditions provided that:</p><p><strong>(i)</strong> the Health Service must pay to the Doctor no less than the rates of pay specified in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> and all other monetary payments required to be paid under this Agreement for the performance of all work to which this Agreement applies; and</p><p><strong>(ii)</strong> the Health Service must not pay, and the Doctor must not seek or accept, any increase in the agreed rates of pay or monetary payments to apply at the time the Doctor commenced in the New Position which exceed the percentage increase in the rates of pay and monetary payments specified in this clause and Part 1 of</p><p><strong>31.9</strong> New Doctors, and Existing Doctors who change Health Services</p><p><strong>(a)</strong> Where a Health Service employs a New Doctor, or an Existing Doctor changes Health Service while this Agreement is in operation, the new Health Service may offer employment to that New Doctor or Existing Doctor on such terms and conditions as may be agreed between them provided that:</p><p><strong>(i)</strong> the Health Service must pay to the Doctor no less than the rates of pay specified in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> and all other monetary payments required to be paid under this Agreement for the performance of all work to which this Agreement applies; and</p><p><strong>(ii)</strong> the Health Service must not pay, and the Doctor must not seek or accept, any increase in the agreed rates of pay or monetary payments to apply at the time the Existing Doctor commenced employment with the new Health Service which exceed the percentage increase in the rates of pay and monetary payments specified in this clause and <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> to apply under this Agreement.</p><p><strong>31.10</strong> Restructures within Health Services</p><p><strong>(a)</strong> Where a Health Service initiates major changes to its organisation or service delivery, which have a significant impact on the responsibilities or work patterns of Doctors which genuinely result in:</p><p><strong>(i)</strong> the creation of new roles (within the scope of this Agreement); or</p><p><strong>(ii)</strong> substantive changes to existing roles, with a significant net addition to work requirements for those roles,</p><p>the Health Service may collectively negotiate with the affected Doctors revised terms and conditions of employment provided that:</p><p><strong>(iii)</strong> the Health Service must pay to each Doctor no less than the rates of pay specified in <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> and all other monetary payments required to be paid under this Agreement for the performance of all work to which this Agreement applies; and</p><p><strong>(iv)</strong> the Health Service must not pay, and a Doctor must not seek or accept, any increase in the agreed rates of pay or monetary payments to apply at the time the collectively agreed arrangements commence which exceed the percentage increases</p><p>in the rates of pay specified in this clause and <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> to apply under this Agreement.</p><p><strong>31.11</strong> General Rule</p><p><strong>(a)</strong> Except as provided in subclauses 31.7, 31.8, 31.9 and 31.10, it is a requirement of this Agreement that while this Agreement is in operation:</p><p><strong>(i)</strong> the Health Services must pay to all Doctors the rates of pay specified in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a> and all other monetary payments required to be paid under this Agreement for the performance of all work to which this Agreement applies;</p><p><strong>(ii)</strong> the Health Services must not pay, and a Doctor must not seek or accept, any payment for the performance of work to which this Agreement applies in excess of, or less than, the rates of pay specified in Part 1 of <a href="/eba/ebas/medical-specialists/appendices/2-specialists-remuneration-and-allowances.html">Appendix 2</a>, unless such payment is otherwise required to be paid by a term of this Agreement or by the Act;</p><p><strong>(iii)</strong> a Health Service must not pay to a Doctor, and a Doctor must not seek or accept, any monetary payment in consideration for the performance of work to which this Agreement applies, other than the monetary payments required to be paid under this Agreement or under the Act; and</p><p><strong>(iv)</strong> a Doctor must not make any further claims for increases in rates of pay or any other form of monetary payment (whether payable by way of contract or otherwise) while this Agreement is in operation.</p><p><strong>31.12</strong> For the purpose of this clause:</p><p><strong>(a)</strong> an &#39;Existing Doctor&#39; is a Doctor who is employed by a Health Service as at the date this Agreement commences to operate;</p><p><strong>(b)</strong> a &#39;New Doctor&#39; is a person who is not employed by a Health Service as at the date this Agreement commences to operate, who first becomes employed as a Doctor while this Agreement is in operation;</p><p><strong>(c)</strong> &#39;monetary payments&#39; includes but is not limited to salary, superannuation contributions, allowances, other forms of remuneration, other elements of the Doctor&#39;s terms and conditions package, and any (or any other) non-salary employment benefits which are convertible into remuneration.</p><p>Plain language terms: pay, pay rise, salary increase.</p>',44)])])}const g=t(o,[["render",i]]);export{d as __pageData,g as default};
